// Preserve channel context for use after HTTP call
const items = $input.all();
return items.map(item => ({
  json: {
    channel_id: item.json.channel_id,
    account_id: item.json.account_id,
    access_token: item.json.access_token,
    cursor: null,
    has_more: true,
    videos: []
  }
}));

// Merge API response with upstream channel context
// $input.all() has HTTP response; use $('Init - Channel State').all() for channel context
const apiItems = $input.all();
const channelItems = $('Init - Channel State').all();

const transformed = [];

apiItems.forEach((apiItem, idx) => {
  const channel = channelItems[idx]?.json || {};
  const videos = apiItem.json.data?.videos || [];
  const hasMore = apiItem.json.data?.has_more || false;
  const cursor = apiItem.json.data?.cursor || null;

  const views = videos.reduce((s, v) => s + (v.view_count || 0), 0);
  const likes = videos.reduce((s, v) => s + (v.like_count || 0), 0);
  const comments = videos.reduce((s, v) => s + (v.comment_count || 0), 0);
  const shares = videos.reduce((s, v) => s + (v.share_count || 0), 0);
  const downloads = videos.reduce((s, v) => s + (v.download_count || 0), 0);
  const engagement = likes + comments + shares + downloads;

  transformed.push({
    json: {
      channel_id: channel.channel_id,
      access_token: channel.access_token,
      has_more: hasMore,
      cursor: cursor,
      platform: 'tiktok',
      metric_date: new Date().toISOString().split('T')[0],
      reach: parseInt(views),
      impressions: 0,
      engagements: parseInt(engagement),
      clicks: 0,
      likes: parseInt(likes),
      comments: parseInt(comments),
      shares: parseInt(shares),
      saves: parseInt(downloads),
      video_views: parseInt(views),
      watch_time_seconds: 0,
      profile_visits: 0,
      follower_count: 0,
      created_at: new Date().toISOString()
    }
  });
});

return transformed;
